import React, { useState, useEffect, useRef } from 'react';
import { NAV_STRUCTURE, LANGUAGES, DEFAULT_PIPELINE } from './constants';
import { Company, SearchParams, SavedList, Deal, CardVisibilityConfig, Pipeline } from './types';
import { fetchEnrichedLeads } from './services/geminiService';
import { fetchBrazilianCities, CityOption } from './services/locationService';
import { translations, Language } from './utils/i18n';
import LeadCard from './components/LeadCard';
import LeadListView from './components/LeadListView';
import SelectListModal from './components/SelectListModal';
import DealDetailsModal from './components/DealDetailsModal';
import SettingsModal from './components/SettingsModal';
import LoadingBar from './components/LoadingBar';
import LoginScreen from './components/LoginScreen';
import { useAuth } from './contexts/AuthContext';
import { Search, Loader2, Hexagon, Save, LayoutGrid, List, Download, ChevronDown, MapPin, ChevronLeft, ChevronRight, Globe, Check, AlertTriangle, AlertOctagon, Pin, PinOff, Bell, User, Settings as SettingsIcon, PanelLeftOpen, PanelLeftClose, Filter, Plus, Kanban, MessageSquare, BarChart3, Mail, MoreVertical, SlidersHorizontal, ArrowUpRight, MoreHorizontal, Clock, GripHorizontal, Building, Phone, ArrowUpDown, Globe2, Trash2, X, RefreshCw, Calendar, Palette, GitBranch, LogOut, Crown, Lock, Hash } from 'lucide-react';

const ITEMS_PER_PAGE = 50;

// Helper function for fuzzy matching (removes accents/diacritics)
const normalizeText = (text: string) => {
  return text.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
};

// Helper for safe UUID generation
const generateUUID = () => {
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
        return crypto.randomUUID();
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
};

const App: React.FC = () => {
  const { user, isAuthenticated, logout, loading: authLoading, incrementUsage } = useAuth();

  // --- LAYOUT STATE ---
  const [activeModuleId, setActiveModuleId] = useState('explore'); 
  const [isSidebarPinned, setIsSidebarPinned] = useState(false);
  const [isSidebarHovered, setIsSidebarHovered] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const isSidebarExpanded = isSidebarPinned || isSidebarHovered;

  // --- DATA STATE ---
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid'); 
  const [searchParams, setSearchParams] = useState<SearchParams>({ city: '', segment: '' });
  const [quantityInput, setQuantityInput] = useState(''); 

  const [leads, setLeads] = useState<Company[]>([]);

  // Loading States
  const [loading, setLoading] = useState(false); 
  const [isLoadingMore, setIsLoadingMore] = useState(false); 
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingStatus, setLoadingStatus] = useState('');

  const [hasSearched, setHasSearched] = useState(false);
  const [hasMoreResults, setHasMoreResults] = useState(true); 
  const [error, setError] = useState<string | null>(null);
  const [localSearchTerm, setLocalSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [savedLists, setSavedLists] = useState<SavedList[]>([]);
  const [activeListId, setActiveListId] = useState<string | null>(null);

  // --- PIPELINE & CRM STATE ---
  const [pipelines, setPipelines] = useState<Pipeline[]>([DEFAULT_PIPELINE]);
  // Use first pipeline or fallback to default safely
  const activePipeline = pipelines[0] || DEFAULT_PIPELINE;

  const [pipelineDeals, setPipelineDeals] = useState<Deal[]>([]);
  const [contacts, setContacts] = useState<Company[]>([]);
  const [selectedDeal, setSelectedDeal] = useState<Deal | null>(null);
  const [isDealModalOpen, setIsDealModalOpen] = useState(false);

  // Pipeline Settings
  const [cardVisibility, setCardVisibility] = useState<CardVisibilityConfig>({
      showId: true,
      showContactInfo: true,
      showLocation: true,
      showValue: true,
      showPriority: true,
      showDate: true,
      showTags: true
  });

  const [pipelineFilterTerm, setPipelineFilterTerm] = useState('');
  const [pipelineFilterPriority, setPipelineFilterPriority] = useState<string>('all');
  const [pipelineFilterPeriod, setPipelineFilterPeriod] = useState<string>('all');

  // --- MODALS ---
  const [isSaveListModalOpen, setIsSaveListModalOpen] = useState(false);
  const [listNameInput, setListNameInput] = useState('');
  const [isSelectListModalOpen, setIsSelectListModalOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
  const [leadToSave, setLeadToSave] = useState<Company | null>(null);

  // --- I18N ---
  const [currentLang, setCurrentLang] = useState<Language>('pt');
  const [showLangMenu, setShowLangMenu] = useState(false);
  const t = translations[currentLang];

  // --- CITY AUTOCOMPLETE ---
  const [allCities, setAllCities] = useState<CityOption[]>([]);
  const [filteredCities, setFilteredCities] = useState<CityOption[]>([]);
  const [showCitySuggestions, setShowCitySuggestions] = useState(false);
  const [citiesLoading, setCitiesLoading] = useState(true);
  const [validCitySelected, setValidCitySelected] = useState(false);
  const cityInputRef = useRef<HTMLDivElement>(null);
  const progressInterval = useRef<any>(null);

  // --- INIT ---
  useEffect(() => {
    if (!isAuthenticated) return;

    const loadCities = async () => {
      setCitiesLoading(true);
      const cities = await fetchBrazilianCities();
      setAllCities(cities);
      setCitiesLoading(false);
    };
    loadCities();

    // Load Saved Lists
    const saved = localStorage.getItem('nexus_saved_lists');
    if (saved) {
        try { setSavedLists(JSON.parse(saved)); } catch(e) {}
    }

    // Load Pipelines
    const savedPipelines = localStorage.getItem('nexus_pipelines');
    if (savedPipelines) {
        try { 
            const parsed = JSON.parse(savedPipelines);
            if(parsed.length > 0) setPipelines(parsed);
            else setPipelines([DEFAULT_PIPELINE]);
        } catch(e) {
            setPipelines([DEFAULT_PIPELINE]);
        }
    }

    // Load Pipeline Deals
    const savedDeals = localStorage.getItem('nexus_pipeline_deals');
    if (savedDeals) {
        try { 
            let deals: Deal[] = JSON.parse(savedDeals);
            // Ensure compatibility with single pipeline
            deals = deals.map(d => ({ ...d, pipelineId: pipelines[0]?.id || DEFAULT_PIPELINE.id }));
            setPipelineDeals(deals);
        } catch(e) {}
    }

    // Load Contacts
    const savedContacts = localStorage.getItem('nexus_contacts');
    if (savedContacts) {
        try { setContacts(JSON.parse(savedContacts)); } catch(e) {}
    }

    // Load Card Config
    const savedCardConfig = localStorage.getItem('nexus_card_visibility');
    if (savedCardConfig) {
        try { setCardVisibility(JSON.parse(savedCardConfig)); } catch(e) {}
    }

    const handleClickOutside = (event: MouseEvent) => {
      if (cityInputRef.current && !cityInputRef.current.contains(event.target as Node)) {
        setShowCitySuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isAuthenticated]);

  // Sync Pipelines
  useEffect(() => {
      if (!isAuthenticated) return;
      localStorage.setItem('nexus_pipelines', JSON.stringify(pipelines));
  }, [pipelines, isAuthenticated]);

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
      setNotification({ message, type });
      setTimeout(() => setNotification(null), 5000); 
  };

  const handleExport = () => {
      showNotification("Exportação CSV iniciada...");
  };

  const handleCityInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setSearchParams(prev => ({ ...prev, city: value }));
    setValidCitySelected(false);

    if (value.length > 0) {
      const normalizedInput = normalizeText(value);

      const filtered = allCities
        .filter(city => {
          const normalizedCity = normalizeText(city.label);
          return normalizedCity.includes(normalizedInput);
        })
        .sort((a, b) => {
           const normA = normalizeText(a.label);
           const normB = normalizeText(b.label);
           if (normA === normalizedInput && normB !== normalizedInput) return -1;
           if (normB === normalizedInput && normA !== normalizedInput) return 1;
           const startsA = normA.startsWith(normalizedInput);
           const startsB = normB.startsWith(normalizedInput);
           if (startsA && !startsB) return -1;
           if (!startsA && startsB) return 1;
           return a.label.localeCompare(b.label);
        })
        .slice(0, 20); 

      setFilteredCities(filtered);
      setShowCitySuggestions(true);
    } else {
      setShowCitySuggestions(false);
    }
  };

  const selectCity = (city: string) => {
    setSearchParams(prev => ({ ...prev, city }));
    setValidCitySelected(true);
    setShowCitySuggestions(false);
  };

  const runProgressSimulation = () => {
     if (progressInterval.current) clearInterval(progressInterval.current);
     setLoadingProgress(0);

     progressInterval.current = setInterval(() => {
        setLoadingProgress((prev) => {
            if (prev >= 90) return prev; 
            if (prev === 20) setLoadingStatus('Analisando empresas encontradas...');
            if (prev === 50) setLoadingStatus('Verificando dados e CNPJs...');
            if (prev === 80) setLoadingStatus('Formatando resultados...');
            const increment = prev < 50 ? 5 : prev < 80 ? 2 : 0.5;
            return prev + increment;
        });
    }, 400);
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validCitySelected || !searchParams.segment) return;

    const desiredQuantity = quantityInput ? parseInt(quantityInput) : 9;

    // Reset State
    setLoading(true);
    setLoadingStatus('Iniciando busca no Google Maps...');
    setHasSearched(true);
    setHasMoreResults(true); 
    setError(null);
    setLeads([]);
    setCurrentPage(1);
    setLocalSearchTerm('');
    setShowCitySuggestions(false);
    setActiveListId(null);

    runProgressSimulation();

    try {
        const results = await fetchEnrichedLeads(searchParams.city, searchParams.segment, [], desiredQuantity);

        // INCREMENT QUOTA (Free App - just tracking)
        incrementUsage(results.length);

        setLeads(results);
        if (results.length === 0) setHasMoreResults(false);
        setLoadingProgress(100);
        setLoadingStatus('Concluído!');
    } catch (err) {
        setError("Falha ao buscar empresas. Tente novamente.");
        setLoadingProgress(0);
    } finally {
        clearInterval(progressInterval.current);
        setTimeout(() => setLoading(false), 500);
    }
  };

  const handleLoadMore = async () => {
    if (!hasMoreResults || isLoadingMore) return;

    const desiredQuantity = quantityInput ? parseInt(quantityInput) : 9;

    setIsLoadingMore(true);
    setLoadingStatus('Buscando mais empresas...');
    runProgressSimulation();

    try {
        const currentNames = leads.map(l => l.nome_fantasia);
        const newResults = await fetchEnrichedLeads(
            searchParams.city, 
            searchParams.segment, 
            currentNames,
            desiredQuantity
        );

        const uniqueNewResults = newResults.filter(
            newLead => !leads.some(
                existing => normalizeText(existing.nome_fantasia) === normalizeText(newLead.nome_fantasia)
            )
        );

        incrementUsage(uniqueNewResults.length);

        if (uniqueNewResults.length === 0) {
            if(newResults.length === 0) {
                setHasMoreResults(false);
                showNotification("Não encontramos mais resultados únicos para este termo.", "error");
            } else {
                 showNotification("Resultados duplicados filtrados. Tente novamente para novos.", "error");
            }
        } else {
            setLeads(prev => [...prev, ...uniqueNewResults]);
            setLoadingProgress(100);
        }
    } catch (err) {
        showNotification("Erro ao carregar mais resultados.", "error");
    } finally {
        clearInterval(progressInterval.current);
        setTimeout(() => setIsLoadingMore(false), 500);
    }
  };

  const filteredLeads = leads.filter(lead => {
     if (localSearchTerm) {
         const term = normalizeText(localSearchTerm);
         return normalizeText(lead.nome_fantasia).includes(term) || normalizeText(lead.razão_social).includes(term);
     }
     return true;
  });

  const currentLeads = filteredLeads; 

  const handleSaveSingleLead = (lead: Company) => { setLeadToSave(lead); setIsSelectListModalOpen(true); };

  const confirmSaveLeadToList = (listId: string | 'NEW', newListName?: string) => {
      if (!leadToSave) return;
      let updatedLists = [...savedLists];
      if (listId === 'NEW' && newListName) {
          const newList: SavedList = {
              id: Date.now().toString(),
              name: newListName,
              createdAt: new Date().toLocaleDateString(),
              leads: [leadToSave],
              params: { city: leadToSave.cidade, segment: leadToSave.atividade_principal }
          };
          updatedLists = [newList, ...updatedLists];
      } else {
          updatedLists = updatedLists.map(list => {
              if (list.id === listId) {
                  const exists = list.leads.some(l => l.id === leadToSave.id);
                  if (!exists) return { ...list, leads: [...list.leads, leadToSave] };
              }
              return list;
          });
      }
      setSavedLists(updatedLists);
      localStorage.setItem('nexus_saved_lists', JSON.stringify(updatedLists));
      setIsSelectListModalOpen(false);
      setLeadToSave(null);
      showNotification(t.lead_saved_success);
  };

  const handleOpenList = (list: SavedList) => {
      setLeads(list.leads);
      setSearchParams(list.params);
      setHasSearched(true);
      setActiveListId(list.id);
      setActiveModuleId('explore'); 
      setValidCitySelected(true);
      setHasMoreResults(false); 
  };

  const confirmSaveBatchList = (e: React.FormEvent) => {
      e.preventDefault();
      const finalName = listNameInput.trim() || `${searchParams.segment} - ${searchParams.city}`;
      const newList: SavedList = {
          id: Date.now().toString(),
          name: finalName,
          createdAt: new Date().toLocaleDateString(),
          leads: [...leads],
          params: { ...searchParams }
      };
      const updatedLists = [newList, ...savedLists];
      setSavedLists(updatedLists);
      localStorage.setItem('nexus_saved_lists', JSON.stringify(updatedLists));
      setIsSaveListModalOpen(false);
      showNotification(t.list_saved_success);
  };

  // --- PIPELINE & CRM MANAGEMENT ---
  const handleQuickAddToPipeline = (company: Company) => {
      try {
          const targetPipeline = pipelines[0];

          if (!targetPipeline) {
             showNotification("Erro: Nenhum pipeline configurado.", "error");
             return;
          }

          if (pipelineDeals.some(d => d.companyId === company.id)) {
              showNotification("Esta empresa já possui um negócio ativo.", "error");
              return;
          }

          if (targetPipeline.stages.length === 0) {
              showNotification("Funil sem etapas definidas.", "error");
              return;
          }

          const firstStageId = targetPipeline.stages[0].id;
          const newDeal: Deal = {
              id: generateUUID(),
              companyId: company.id,
              companyName: company.nome_fantasia,
              pipelineId: targetPipeline.id,
              stage: firstStageId, 
              value: 0, 
              priority: Math.random() > 0.7 ? 'Alta' : Math.random() > 0.4 ? 'Média' : 'Baixa',
              createdAt: new Date().toISOString(),
              contactInfo: {
                  phone: company.telefone,
                  website: company.website,
                  location: company.endereco || `${company.cidade}, ${company.uf}` 
              },
              customFields: []
          };

          const updatedDeals = [...pipelineDeals, newDeal];
          setPipelineDeals(updatedDeals);
          localStorage.setItem('nexus_pipeline_deals', JSON.stringify(updatedDeals));

          if (!contacts.some(c => c.id === company.id)) {
              const updatedContacts = [...contacts, company];
              setContacts(updatedContacts);
              localStorage.setItem('nexus_contacts', JSON.stringify(updatedContacts));
          }

          showNotification(`Negócio criado em: ${targetPipeline.name}`);

      } catch (error) {
          console.error("Erro ao adicionar ao pipeline:", error);
          showNotification("Erro ao criar negócio. Tente novamente.", "error");
      }
  };

  // NEW: Add a deal directly to a stage column
  const handleAddDealToStage = (stageId: string) => {
      const newDeal: Deal = {
          id: generateUUID(),
          companyId: generateUUID(), // Temporary dummy ID
          companyName: "Novo Negócio",
          pipelineId: activePipeline.id,
          stage: stageId,
          value: 0,
          priority: 'Média',
          createdAt: new Date().toISOString(),
          contactInfo: { location: "Localização" },
          customFields: []
      };

      const updatedDeals = [...pipelineDeals, newDeal];
      setPipelineDeals(updatedDeals);
      localStorage.setItem('nexus_pipeline_deals', JSON.stringify(updatedDeals));

      // Auto-open modal to edit details
      setSelectedDeal(newDeal);
      setIsDealModalOpen(true);
  };

  // NEW: Global "Create New" handler for the header button
  const handleGlobalCreateNew = () => {
      const target = pipelines.length > 0 ? pipelines[0] : DEFAULT_PIPELINE;
      if (target && target.stages.length > 0) {
          handleAddDealToStage(target.stages[0].id);
      } else {
          showNotification("Pipeline sem etapas definidas.", "error");
      }
  };

  const handleDragStart = (e: React.DragEvent, dealId: string) => {
      e.dataTransfer.setData("dealId", dealId);
      e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, targetStageId: string) => {
      e.preventDefault();
      const dealId = e.dataTransfer.getData("dealId");

      const updatedDeals = pipelineDeals.map(deal => {
          if (deal.id === dealId) {
              return { ...deal, stage: targetStageId };
          }
          return deal;
      });

      setPipelineDeals(updatedDeals);
      localStorage.setItem('nexus_pipeline_deals', JSON.stringify(updatedDeals));
  };

  const handleDealClick = (deal: Deal) => {
      setSelectedDeal(deal);
      setIsDealModalOpen(true);
  };

  const handleContactClick = (contact: Company) => {
      const existingDeal = pipelineDeals.find(d => d.companyId === contact.id);

      if (existingDeal) {
          setSelectedDeal(existingDeal);
      } else {
          const newDeal: Deal = {
            id: generateUUID(),
            companyId: contact.id,
            companyName: contact.nome_fantasia,
            pipelineId: activePipeline.id,
            stage: activePipeline.stages[0].id, 
            value: 0,
            priority: 'Média',
            createdAt: new Date().toISOString(),
            contactInfo: {
                phone: contact.telefone,
                website: contact.website,
                location: contact.endereco || `${contact.cidade}, ${contact.uf}`
            },
            customFields: []
        };
        setSelectedDeal(newDeal);
      }
      setIsDealModalOpen(true);
  };

  const handleUpdateDeal = (updatedDeal: Deal) => {
      const exists = pipelineDeals.some(d => d.id === updatedDeal.id);
      let updatedDeals;

      if (exists) {
          updatedDeals = pipelineDeals.map(d => d.id === updatedDeal.id ? updatedDeal : d);
      } else {
          updatedDeals = [...pipelineDeals, updatedDeal];
      }

      setPipelineDeals(updatedDeals);
      localStorage.setItem('nexus_pipeline_deals', JSON.stringify(updatedDeals));

      // Also update contacts if linked
      const updatedContacts = contacts.map(contact => {
          if (contact.id === updatedDeal.companyId) {
             return {
                 ...contact,
                 nome_fantasia: updatedDeal.companyName, // In case name changed
                 telefone: updatedDeal.contactInfo?.phone,
                 website: updatedDeal.contactInfo?.website,
                 endereco: updatedDeal.contactInfo?.location 
             };
          }
          return contact;
      });
      setContacts(updatedContacts);
      localStorage.setItem('nexus_contacts', JSON.stringify(updatedContacts));

      showNotification('Negócio atualizado com sucesso!');
  };

  const handleDeleteDeal = (dealId: string) => {
      const updatedDeals = pipelineDeals.filter(d => d.id !== dealId);
      setPipelineDeals(updatedDeals);
      localStorage.setItem('nexus_pipeline_deals', JSON.stringify(updatedDeals));
      showNotification('Negócio removido.');
  };

  const handleUpdateCardConfig = (key: keyof CardVisibilityConfig) => {
      const newConfig = { ...cardVisibility, [key]: !cardVisibility[key] };
      setCardVisibility(newConfig);
      localStorage.setItem('nexus_card_visibility', JSON.stringify(newConfig));
  };

  const checkDatePeriod = (dateString: string, period: string) => {
      if (period === 'all') return true;
      const date = new Date(dateString);
      const now = new Date();
      if (period === '7d') {
          const past = new Date();
          past.setDate(now.getDate() - 7);
          return date >= past;
      }
      if (period === '30d') {
          const past = new Date();
          past.setDate(now.getDate() - 30);
          return date >= past;
      }
      if (period === 'this_month') {
          return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
      }
      return true;
  };

  const renderExploreView = () => (
      <div className="space-y-6">
          <div className="bg-white rounded border border-gray-200 shadow-sm p-5">
              <div className="flex flex-col md:flex-row gap-5 items-end">
                   <div className="flex-[2] w-full relative group" ref={cityInputRef}>
                        <label className="block text-xs font-bold text-nexus-dark mb-2">Localização <span className="text-red-500">*</span></label>
                        <div className="relative">
                            <MapPin className={`absolute left-3 top-3 h-4 w-4 ${validCitySelected ? 'text-nexus-royal' : 'text-gray-400'}`} />
                            <input 
                                type="text"
                                placeholder={t.search_city_placeholder}
                                className={`w-full h-11 pl-10 pr-4 bg-white border rounded text-sm outline-none focus:ring-2 focus:ring-nexus-royal/20 transition-all ${!validCitySelected && searchParams.city.length > 0 ? 'border-red-300' : 'border-gray-300 focus:border-nexus-royal'}`}
                                value={searchParams.city}
                                onChange={handleCityInputChange}
                                onFocus={() => { if(searchParams.city.length > 0) setShowCitySuggestions(true); }}
                            />
                        </div>
                         {showCitySuggestions && filteredCities.length > 0 && (
                              <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-md shadow-xl max-h-64 overflow-y-auto z-[100]">
                                {filteredCities.map((city) => (
                                  <button key={city.value} onClick={() => selectCity(city.value)} className="w-full text-left px-4 py-3 text-sm text-gray-700 hover:bg-blue-50 border-b border-gray-50 last:border-0">
                                    {city.label}
                                  </button>
                                ))}
                              </div>
                         )}
                   </div>

                   <div className="flex-[2] w-full">
                        <label className="block text-xs font-bold text-nexus-dark mb-2">Segmento / Indústria <span className="text-red-500">*</span></label>
                        <div className="relative">
                            <Search className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
                            <input 
                                type="text"
                                placeholder={t.search_segment_placeholder}
                                className="w-full h-11 pl-10 pr-4 bg-white border border-gray-300 rounded text-sm outline-none focus:border-nexus-royal focus:ring-2 focus:ring-nexus-royal/20 transition-all"
                                value={searchParams.segment}
                                onChange={(e) => setSearchParams(prev => ({ ...prev, segment: e.target.value }))}
                                onKeyDown={(e) => e.key === 'Enter' && handleSearch(e)}
                            />
                        </div>
                   </div>

                   <div className="flex-[0.5] w-full min-w-[100px]">
                        <label className="block text-xs font-bold text-nexus-dark mb-2">Qtd</label>
                        <div className="relative">
                            <Hash className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
                            <input 
                                type="number"
                                min="1"
                                max="50"
                                placeholder="9"
                                className="w-full h-11 pl-9 pr-2 bg-white border border-gray-300 rounded text-sm outline-none focus:border-nexus-royal focus:ring-2 focus:ring-nexus-royal/20 transition-all"
                                value={quantityInput}
                                onChange={(e) => setQuantityInput(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleSearch(e)}
                            />
                        </div>
                   </div>

                   <button 
                      onClick={handleSearch}
                      disabled={loading || isLoadingMore || !validCitySelected || !searchParams.segment}
