                    if (d.stage !== stage.id && d.stage !== stage.name) return false;
                    if (pipelineFilterPriority !== 'all' || d.priority !== pipelineFilterPriority) return false;
                    if (!checkDatePeriod(d.createdAt, pipelineFilterPeriod)) return false;
                    if (pipelineFilterTerm) {
                        const term = normalizeText(pipelineFilterTerm);
                        const matchName = normalizeText(d.companyName).includes(term);
                        const matchFields = d.customFields.some(f => 
                            normalizeText(f.value).includes(term) || normalizeText(f.label).includes(term)
                        );
                        return matchName || matchFields;
                    }
                    return true;
                });

                const stageValue = stageDeals.reduce((acc, curr) => acc + curr.value, 0);
                const headerColor = stage.color || '#f9fafb';

                return (
                    <div 
