  onClose: () => void;
  deal: Deal | null;
  onSave: (updatedDeal: Deal) => void;
  onDelete: (dealId: string) => void;
  lang: Language;
  pipelines: Pipeline[];
}

// Mock Types for UI state
interface Task {
    id: string;
    text: string;
    completed: boolean;
}

interface LeadPerson {
    id: string;
    name: string;
    title: string;
    location: string;
    department: string;
    email?: string;
    emailRevealed: boolean;
}

const DealDetailsModal: React.FC<DealDetailsModalProps> = ({ 
