  pipelines 
}) => {
  const t = translations[lang];
  const [formData, setFormData] = useState<Deal | null>(null);

  // Navigation State
  const [activeTab, setActiveTab] = useState('Overview');
  const [insightTab, setInsightTab] = useState('Score');

  // Sidebar State
  const [expandedSections, setExpandedSections] = useState({
    companyDetails: true,
    recordDetails: true,
    tasks: true,
    deals: true
  });

  // Task State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskInput, setNewTaskInput] = useState('');
  const [showTaskInput, setShowTaskInput] = useState(false);

  // Suggested Leads State
  const [people, setPeople] = useState<LeadPerson[]>([]);

  useEffect(() => {
    if (deal) {
      setFormData({ ...deal });
      // Initialize mock people based on company
      setPeople([
          {
              id: '1',
              name: 'Rayane Dias',
              title: `Kitchen Helper @${deal.companyName}`,
              location: deal.contactInfo?.location || 'Brazil',
              department: 'N/A',
              email: `contact@${deal.companyName.toLowerCase().replace(/\s/g, '')}.com`,
              emailRevealed: false
          },
          {
              id: '2',
              name: 'Carlos Manager',
              title: `Owner @${deal.companyName}`,
              location: deal.contactInfo?.location || 'Brazil',
              department: 'Management',
              email: `ceo@${deal.companyName.toLowerCase().replace(/\s/g, '')}.com`,
              emailRevealed: false
          }
      ]);
    }
  }, [deal]);

  if (!isOpen || !formData) return null;

  const toggleSection = (key: keyof typeof expandedSections) => {
    setExpandedSections(prev => ({...prev, [key]: !prev[key]}));
  };

  const handleAddTask = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskInput.trim()) return;
      const newTask: Task = {
          id: Date.now().toString(),
          text: newTaskInput,
          completed: false
      };
      setTasks([...tasks, newTask]);
      setNewTaskInput('');
      setShowTaskInput(false);
  };

  const toggleTask = (taskId: string) => {
      setTasks(tasks.map(t => t.id === taskId ? { ...t, completed: !t.completed } : t));
  };

  const revealEmail = (personId: string) => {
      setPeople(people.map(p => p.id === personId ? { ...p, emailRevealed: true } : p));
  };

  const openWhatsApp = (phone: string | undefined) => {
      if (!phone) return;
      const cleanPhone = phone.replace(/\D/g, '');
      let finalPhone = cleanPhone;
      if (finalPhone.length >= 10 && finalPhone.length <= 11) {
          finalPhone = '55' + finalPhone;
      }
      // Changed from web.whatsapp.com to wa.me to support Desktop App opening
      window.open(`https://wa.me/${finalPhone}`, '_blank');
  };

