                                      )}
                                  </td>
                                  <td className="px-5 py-3 text-right">
                                      <button className="text-gray-400 hover:text-nexus-royal p-1">
                                          <MoreHorizontal className="w-4 h-4" />
                                      </button>
                                  </td>
                              </tr>
                          );
                      })}
                      {contacts.length === 0 && (
                          <tr>
                              <td colSpan={6} className="text-center py-12 text-gray-400 text-sm">
