                    (pipelineFilterPriority === 'all' || d.priority === pipelineFilterPriority) &&
                    (checkDatePeriod(d.createdAt, pipelineFilterPeriod)) &&
                    (normalizeText(d.companyName).includes(normalizeText(pipelineFilterTerm)) ||
