                                            </div>
                                        </div>
                                    )}

                                    <div className="font-bold text-sm text-nexus-dark mb-1 line-clamp-2">{deal.companyName}</div>

                                    {(cardVisibility.showDate || cardVisibility.showLocation) && (
                                        <div className="space-y-0.5 mb-1">
                                             {cardVisibility.showDate && (
                                                <div className="text-xs text-gray-500 flex items-center gap-1">
                                                    <Clock className="w-3 h-3 text-gray-300" /> {deal.createdAt.split('T')[0]}
                                                </div>
                                             )}
                                             {cardVisibility.showLocation && deal.contactInfo?.location && (
                                                 <div className="text-xs text-gray-500 flex items-center gap-1 truncate">
                                                    <MapPin className="w-3 h-3 text-gray-300" /> {deal.contactInfo.location}
                                                 </div>
                                             )}
                                        </div>
                                    )}

                                    {cardVisibility.showContactInfo && (deal.contactInfo?.phone || deal.contactInfo?.website) && (
                                        <div className="flex items-center gap-2 mt-1 mb-1 pb-1 border-b border-gray-50">
                                            {deal.contactInfo.phone && <Phone className="w-3 h-3 text-gray-400" title={deal.contactInfo.phone} />}
                                            {deal.contactInfo.website && <Globe className="w-3 h-3 text-gray-400" title={deal.contactInfo.website} />}
                                        </div>
                                    )}

                                    {cardVisibility.showTags && (
                                        <>
                                            {(pipelineFilterTerm ? 
                                                deal.customFields.filter(f => normalizeText(f.value).includes(normalizeText(pipelineFilterTerm))) : 
                                                deal.customFields.slice(0, 2) 
                                            ).length > 0 && (
                                                <div className="mt-2 pt-1 border-t border-gray-100 flex flex-wrap gap-1">
                                                    {(pipelineFilterTerm ? 
                                                        deal.customFields.filter(f => normalizeText(f.value).includes(normalizeText(pipelineFilterTerm))) : 
                                                        deal.customFields.slice(0, 2)
                                                    ).map(f => (
                                                        <div key={f.id} className="text-[9px] text-gray-600 bg-gray-50 px-1.5 rounded truncate max-w-full">
                                                            {f.label}: {f.value}
                                                        </div>
                                                    ))}
                                                    {!pipelineFilterTerm && deal.customFields.length > 2 && (
                                                        <span className="text-[9px] text-gray-400">+{deal.customFields.length - 2}</span>
                                                    )}
                                                </div>
                                            )}
                                        </>
                                    )}

                                    {cardVisibility.showValue && (
                                        <div className="mt-2 pt-2 border-t border-gray-100 flex items-center justify-between">
                                                <div className="w-5 h-5 rounded-full bg-blue-100 text-blue-700 flex items-center justify-center text-[9px] font-bold">JS</div>
                                                <span className="text-xs font-bold text-gray-700">
                                                    {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(deal.value)}
                                                </span>
                                        </div>
                                    )}
                                </div>
                            ))}
                            {stageDeals.length === 0 && (
                                <div className="text-center py-4 text-xs text-gray-400 italic border-2 border-dashed border-gray-200 rounded m-2">
                                    Solte aqui
                                </div>
                            )}
                            <button 
                                onClick={() => handleAddDealToStage(stage.id)}
                                className="w-full py-2 text-xs font-bold text-gray-500 hover:text-nexus-royal hover:bg-white rounded border border-transparent hover:border-gray-200 hover:shadow-sm transition-all flex items-center justify-center gap-1"
                            >
                                <Plus className="w-3 h-3" /> Adicionar Negócio
                            </button>
                        </div>
                    </div>
                );
            })}
          </div>
      </div>
    );
  };

  const renderContactsView = () => (
      <div className="bg-white border border-gray-200 rounded shadow-sm overflow-hidden animate-fadeIn">
          <div className="p-5 border-b border-gray-200 flex justify-between items-center bg-gray-50">
               <div>
                   <h2 className="text-lg font-bold text-nexus-dark">Todos os Contatos</h2>
                   <p className="text-xs text-gray-500">Gerencie sua base de relacionamentos.</p>
               </div>
               <div className="text-xs font-bold text-gray-500 bg-white px-3 py-1 border rounded shadow-sm">
                   Total: {contacts.length}
               </div>
          </div>
          <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                  <thead>
                      <tr className="bg-white border-b border-gray-200 text-xs font-bold text-gray-500 uppercase tracking-wide">
                          <th className="px-5 py-3 w-10"><input type="checkbox" className="rounded" /></th>
                          <th className="px-5 py-3">Empresa / Nome</th>
                          <th className="px-5 py-3">Email / Telefone</th>
                          <th className="px-5 py-3">Localização</th>
                          <th className="px-5 py-3">Pipeline Status</th>
                          <th className="px-5 py-3"></th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                      {contacts.map(contact => {
                          const activeDeal = pipelineDeals.find(d => d.companyId === contact.id);
                          const currentPipeline = activeDeal ? pipelines.find(p => p.id === activeDeal.pipelineId) : null;

                          return (
                              <tr 
                                key={contact.id} 
                                onClick={() => handleContactClick(contact)}
                                className="hover:bg-blue-50/50 transition-colors group cursor-pointer"
                              >
                                  <td className="px-5 py-3" onClick={(e) => e.stopPropagation()}><input type="checkbox" className="rounded" /></td>
                                  <td className="px-5 py-3">
                                      <div className="flex items-center gap-3">
                                          <div className="w-8 h-8 rounded-full bg-nexus-royal/10 text-nexus-royal flex items-center justify-center text-xs font-bold shrink-0">
                                              {contact.nome_fantasia.charAt(0)}
                                          </div>
                                          <div className="truncate max-w-[200px]">
                                              <div className="font-bold text-sm text-nexus-dark">{contact.nome_fantasia}</div>
                                              <div className="text-xs text-gray-400">{contact.razão_social}</div>
                                          </div>
                                      </div>
                                  </td>
                                  <td className="px-5 py-3">
                                      <div className="flex flex-col gap-1">
                                          {contact.telefone ? (
                                              <div className="flex items-center gap-2 text-xs text-gray-700">
                                                  <Phone className="w-3 h-3 text-gray-400" /> {contact.telefone}
                                              </div>
                                          ) : <span className="text-xs text-gray-400">--</span>}
                                          {contact.website ? (
                                              <div className="flex items-center gap-2 text-xs text-nexus-royal cursor-pointer hover:underline truncate max-w-[150px]">
                                                  <Globe2 className="w-3 h-3 text-gray-400" /> {contact.website}
                                              </div>
                                          ) : <span className="text-xs text-gray-400">--</span>}
                                      </div>
                                  </td>
                                  <td className="px-5 py-3">
                                      <div className="text-xs text-gray-700 line-clamp-1" title={contact.endereco || contact.cidade}>
                                          {contact.endereco || contact.cidade}
                                      </div>
                                      <div className="text-[10px] text-gray-400">{contact.uf}</div>
                                  </td>
                                  <td className="px-5 py-3">
                                      {activeDeal ? (
                                          <div className="flex flex-col gap-0.5">
                                            <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-blue-50 text-blue-700 border border-blue-100 uppercase tracking-wide w-fit">
                                                {activeDeal.stage}
                                            </span>
                                            {currentPipeline && (
                                                <span className="text-[9px] text-gray-400">{currentPipeline.name}</span>
                                            )}
                                          </div>
                                      ) : (
                                          <span className="text-xs text-gray-400 italic">Sem negócio ativo</span>
                                      )}
                                  </td>
                                  <td className="px-5 py-3 text-right">
                                      <button className="text-gray-400 hover:text-nexus-royal p-1">
                                          <MoreHorizontal className="w-4 h-4" />
                                      </button>
                                  </td>
                              </tr>
                          );
                      })}
                      {contacts.length === 0 && (
                          <tr>
                              <td colSpan={6} className="text-center py-12 text-gray-400 text-sm">
                                  Nenhum contato salvo ainda. Adicione empresas ao Pipeline para criar contatos.
                              </td>
                          </tr>
                      )}
                  </tbody>
              </table>
          </div>
      </div>
  );

  if (authLoading) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-nexus-bg">
              <Loader2 className="w-8 h-8 text-nexus-royal animate-spin" />
          </div>
      );
  }

  if (!isAuthenticated) {
      return <LoginScreen />;
  }

  return (
    <div className="min-h-screen bg-nexus-bg font-sans flex text-nexus-dark overflow-hidden">

      <aside 
         className={`bg-nexus-sidebar text-white flex flex-col transition-all duration-300 ease-in-out z-50 shadow-xl border-r border-gray-800 ${isSidebarExpanded ? 'w-64' : 'w-16'}`}
         onMouseEnter={() => !isSidebarPinned && setIsSidebarHovered(true)}
         onMouseLeave={() => !isSidebarPinned && setIsSidebarHovered(false)}
      >
          <div className="h-14 flex items-center px-4 border-b border-white/10 shrink-0 bg-nexus-sidebarHover">
               <div className="w-8 h-8 bg-nexus-royal rounded flex items-center justify-center shrink-0 shadow-sm">
                    <Hexagon size={18} fill="currentColor" className="text-white" />
               </div>
               <div className={`ml-3 overflow-hidden transition-opacity duration-300 ${isSidebarExpanded ? 'opacity-100' : 'opacity-0 w-0'}`}>
                   <h1 className="font-bold text-lg tracking-tight whitespace-nowrap">NEXUS CRM</h1>
               </div>
          </div>

          <div className="flex-1 overflow-y-auto py-4 space-y-6 scrollbar-hide">
              {NAV_STRUCTURE.map((group) => (
                  <div key={group.title}>
                      {isSidebarExpanded && (
                          <div className="px-5 mb-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider animate-fadeIn">
                              {group.title}
                          </div>
                      )}
                      {!isSidebarExpanded && <div className="mx-4 mb-2 border-t border-white/10"></div>}

                      <div className="space-y-0.5 px-2">
                          {group.items.map(item => (
                              <button
                                 key={item.id}
                                 onClick={() => setActiveModuleId(item.id)}
                                 className={`w-full flex items-center h-9 px-3 rounded transition-all duration-200 group relative ${
                                     activeModuleId === item.id 
                                     ? 'bg-nexus-royal text-white shadow-md font-medium' 
                                     : 'text-slate-300 hover:bg-white/10 hover:text-white'
                                 }`}
                              >
                                  <item.icon className={`w-4 h-4 shrink-0 transition-colors ${activeModuleId === item.id ? 'text-white' : 'text-slate-400 group-hover:text-white'}`} />
                                  <span className={`ml-3 text-sm whitespace-nowrap transition-all duration-300 ${isSidebarExpanded ? 'opacity-100' : 'opacity-0 absolute left-10 pointer-events-none'}`}>
                                      {item.label}
                                  </span>

                                  {!isSidebarExpanded && (
                                      <div className="absolute left-full ml-2 px-2 py-1 bg-nexus-sidebar text-white text-xs rounded opacity-0 group-hover:opacity-100 pointer-events-none whitespace-nowrap z-50 shadow-xl border border-white/10">
                                          {item.label}
                                      </div>
                                  )}
                              </button>
                          ))}
                      </div>
                  </div>
              ))}
          </div>

          <div className="p-4 border-t border-white/10 shrink-0">
               <button 
                  onClick={() => { setIsSidebarPinned(!isSidebarPinned); setIsSidebarHovered(!isSidebarPinned); }}
                  className="w-full flex items-center justify-center h-8 rounded hover:bg-white/10 text-slate-400 hover:text-white transition-colors"
                  title={isSidebarPinned ? "Unpin Sidebar" : "Pin Sidebar"}
               >
                   {isSidebarPinned ? <PanelLeftClose className="w-5 h-5" /> : <PanelLeftOpen className="w-5 h-5" />}
               </button>
          </div>
      </aside>

      <div className="flex-1 flex flex-col h-screen overflow-hidden relative">

           <header className="h-14 bg-white border-b border-gray-200 flex items-center justify-between px-6 shrink-0 z-40 shadow-sm">
                <div className="flex items-center w-full max-w-xl">
                    <div className="relative w-full">
                        <Search className="absolute left-3 top-2 w-4 h-4 text-gray-400" />
                        <input 
                            type="text" 
                            placeholder="Pesquisar no Nexus CRM (Ctrl+K)" 
                            className="w-full h-8 pl-9 pr-4 bg-gray-100 border border-transparent rounded text-sm focus:bg-white focus:border-nexus-royal focus:ring-2 focus:ring-nexus-royal/20 transition-all outline-none placeholder-gray-500 text-gray-700"
                        />
                    </div>
                </div>

                <div className="flex items-center gap-4 ml-6">
                    <button className="p-1.5 text-gray-500 hover:bg-gray-100 rounded-full relative transition-colors">
                        <Bell className="w-5 h-5" />
                        <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
                    </button>
                    <button 
                        onClick={() => setIsSettingsModalOpen(true)}
                        className="p-1.5 text-gray-500 hover:bg-gray-100 rounded-full transition-colors"
                    >
                        <SettingsIcon className="w-5 h-5" />
                    </button>

                    <div className="relative group cursor-pointer">
                        <div className="w-8 h-8 rounded-full overflow-hidden border border-gray-200 shadow-sm hover:ring-2 ring-offset-2 ring-nexus-royal transition-all">
                            {user?.avatar ? (
                                <img src={user.avatar} alt="User" className="w-full h-full object-cover" />
                            ) : (
                                <div className="w-full h-full bg-nexus-royal text-white flex items-center justify-center font-bold text-xs">
                                    {user?.name.charAt(0).toUpperCase()}
                                </div>
                            )}
                        </div>
                        <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-lg shadow-xl border border-gray-100 p-2 hidden group-hover:block animate-fadeIn z-50">
                            <div className="px-3 py-2 border-b border-gray-100 mb-2">
                                <p className="text-sm font-bold text-nexus-dark truncate">{user?.name}</p>
                                <p className="text-[10px] text-gray-500 truncate">{user?.email}</p>
                                <span className="inline-block mt-1 px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-nexus-royal/10 text-nexus-royal">
                                    {user?.plan} PLAN
                                </span>
                            </div>
                            <button onClick={logout} className="w-full text-left px-3 py-2 text-xs font-medium text-red-500 hover:bg-red-50 rounded flex items-center gap-2">
                                <LogOut className="w-3.5 h-3.5" /> Sair da conta
                            </button>
                        </div>
                    </div>
                </div>
           </header>

           <div className="h-16 border-b border-gray-200 bg-white px-8 flex items-center justify-between shrink-0">
                <div className="flex flex-col justify-center">
                    <div className="flex items-center gap-2 text-xs mb-0.5">
                        <span className="font-semibold text-gray-500 uppercase tracking-wide">
                            {NAV_STRUCTURE.find(g => g.items.some(i => i.id === activeModuleId))?.title}
                        </span>
                        <span className="text-gray-300">/</span>
                    </div>
                    <h1 className="font-bold text-gray-900 text-xl tracking-tight">
                        {NAV_STRUCTURE.flatMap(g => g.items).find(i => i.id === activeModuleId)?.label}
                    </h1>
                </div>
                <div className="flex items-center gap-3">
                     {activeModuleId === 'explore' && (
                         <button className="flex items-center gap-1.5 text-xs font-bold text-nexus-royal bg-white border border-nexus-royal/30 px-4 py-2 rounded shadow-sm hover:bg-blue-50 transition-colors">
                             <Filter className="w-3.5 h-3.5" /> Filtros Salvos
                         </button>
                     )}
                     <button 
                        onClick={handleGlobalCreateNew}
                        className="flex items-center gap-1.5 text-xs font-bold text-white bg-nexus-primary px-5 py-2 rounded hover:bg-orange-600 shadow-sm transition-all border border-transparent"
                     >
                         <Plus className="w-3.5 h-3.5" /> Criar Novo
                     </button>
                </div>
           </div>

           <div className="flex-1 overflow-y-auto p-6 md:p-8 bg-nexus-bg">
                <div className="max-w-[1600px] mx-auto">
                    {activeModuleId === 'explore' && renderExploreView()}
                    {activeModuleId === 'lists' && renderListsView()}
                    {activeModuleId === 'contacts' && renderContactsView()} 
                    {activeModuleId === 'pipeline' && renderPipelineView()}
                    {!['explore', 'lists', 'contacts', 'pipeline'].includes(activeModuleId) && (
                        <div className="flex flex-col items-center justify-center h-96 text-gray-400">
                            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                                <User className="w-8 h-8 text-gray-300" />
                            </div>
                            <h3 className="text-lg font-bold text-gray-600">Módulo em Desenvolvimento</h3>
                            <p>Esta funcionalidade estará disponível na próxima atualização.</p>
                        </div>
                    )}
                </div>
           </div>
      </div>

      {notification && (
          <div className={`fixed bottom-6 right-6 z-[2000] px-6 py-4 rounded shadow-2xl animate-slideIn flex items-center gap-3 border-l-4 max-w-md ${notification.type === 'success' ? 'bg-nexus-sidebar text-white border-nexus-royal' : 'bg-red-50 text-red-800 border-red-500'}`}>
             {notification.type === 'success' ? <Check className="w-5 h-5 text-green-400 shrink-0" /> : <AlertOctagon className="w-5 h-5 shrink-0" />}
             <div>
               <p className="font-bold text-sm mb-0.5">{notification.type === 'success' ? 'Sucesso!' : 'Atenção'}</p>
               <p className="text-xs opacity-90 leading-relaxed">{notification.message}</p>
             </div>
             <button onClick={() => setNotification(null)} className="ml-2 opacity-70 hover:opacity-100">
                 <X className="w-4 h-4" />
             </button>
          </div>
      )}

      {isSaveListModalOpen && (
          <div className="fixed inset-0 z-[1200] flex items-center justify-center bg-nexus-sidebar/50 backdrop-blur-sm p-4 animate-fadeIn">
             <div className="bg-white rounded p-6 w-full max-w-md shadow-2xl border border-gray-100">
                 <h3 className="font-bold text-lg mb-1 text-gray-900">Salvar Lista</h3>
                 <p className="text-xs text-gray-500 mb-4">Crie um novo grupo para organizar seus leads.</p>
                 <input type="text" value={listNameInput} onChange={(e) => setListNameInput(e.target.value)} className="w-full border border-gray-300 p-2.5 rounded mb-4 text-sm focus:border-nexus-royal focus:ring-1 focus:ring-nexus-royal outline-none" placeholder="Nome da lista (Ex: Padarias SP)" autoFocus />
                 <div className="flex justify-end gap-2">
                     <button onClick={() => setIsSaveListModalOpen(false)} className="px-4 py-2 text-gray-600 font-bold text-xs hover:bg-gray-100 rounded transition-colors">Cancelar</button>
                     <button onClick={confirmSaveBatchList} className="px-4 py-2 bg-nexus-primary text-white font-bold text-xs rounded hover:bg-orange-600 transition-colors shadow-sm">Salvar Lista</button>
                 </div>
             </div>
          </div>
      )}

      <SelectListModal 
           isOpen={isSelectListModalOpen}
           onClose={() => setIsSelectListModalOpen(false)}
           onConfirm={confirmSaveLeadToList}
           savedLists={savedLists}
           lang={currentLang}
      />

      <DealDetailsModal 
           isOpen={isDealModalOpen}
           onClose={() => setIsDealModalOpen(false)}
           deal={selectedDeal}
           onSave={handleUpdateDeal}
           onDelete={handleDeleteDeal}
           lang={currentLang}
           pipelines={pipelines}
      />

      <SettingsModal 
           isOpen={isSettingsModalOpen}
           onClose={() => setIsSettingsModalOpen(false)}
           cardConfig={cardVisibility}
           onUpdateCardConfig={handleUpdateCardConfig}
           pipelines={pipelines}
           setPipelines={setPipelines}
      />

    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Company, DataSource } from '../types';
import { Phone, Globe, MapPin, Clock, Copy, MoreHorizontal, Check, Plus, ExternalLink, Building2, Kanban, Map, MessageCircle } from 'lucide-react';
import { translations, Language } from '../utils/i18n';

interface LeadCardProps {
  company: Company;
  lang: Language;
  onSaveClick: (company: Company) => void;
  isSaved?: boolean;
  onAddToPipeline: (company: Company) => void;
  isInPipeline: boolean;
}

const LeadCard: React.FC<LeadCardProps> = ({ company, lang, onSaveClick, isSaved = false, onAddToPipeline, isInPipeline = false }) => {
  const t = translations[lang];
  const [copied, setCopied] = useState(false);

  const copyCnpj = (e: React.MouseEvent) => {
    e.stopPropagation();
    if(company.cnpj === "Consultar" || company.cnpj === "Não Disponível") return;
    navigator.clipboard.writeText(company.cnpj);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const openWebsite = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!company.website) return;
      let url = company.website;
      if (!url.startsWith('http://') && !url.startsWith('https://')) {
          url = 'https://' + url;
      }
      window.open(url, '_blank');
  };

  const openGoogleMaps = (e: React.MouseEvent) => {
      e.stopPropagation();
      const query = encodeURIComponent(`${company.nome_fantasia} ${company.endereco || company.cidade}`);
      window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const openWhatsApp = (e: React.MouseEvent, phone: string) => {
      e.stopPropagation();
      const cleanPhone = phone.replace(/\D/g, '');
      let finalPhone = cleanPhone;
      // Basic logic to ensure BR country code if missing
      if (finalPhone.length >= 10 && finalPhone.length <= 11) {
          finalPhone = '55' + finalPhone;
      }
      // Use whatsapp:// protocol to force Desktop App
      window.open(`whatsapp://send?phone=${finalPhone}`, '_blank');
  };

  const normalize = (s: string) => s ? s.toLowerCase().trim() : '';
  const showLegalName = normalize(company.razão_social) !== normalize(company.nome_fantasia);

  return (
    <div className="group bg-white rounded border border-gray-200 shadow-sm hover:shadow-md transition-all duration-200 flex flex-col h-full overflow-hidden relative">

      {/* Top Border Indicator (HubSpot Style) */}
      <div className="absolute top-0 left-0 right-0 h-1 bg-gray-100 group-hover:bg-nexus-royal transition-colors"></div>

      {/* Header */}
      <div className="p-5 pb-3 flex justify-between items-start">
        <div className="flex-1 pr-4">
            <div className="flex items-center gap-2 mb-1">
                <h3 className="text-base font-bold text-nexus-dark hover:text-nexus-royal cursor-pointer line-clamp-1" title={company.nome_fantasia}>
                    {company.nome_fantasia}
                </h3>
                {company.is_open_now && (
                    <span className="w-2 h-2 rounded-full bg-emerald-500" title={t.status_open}></span>
                )}
            </div>
            {showLegalName && (
                <p className="text-xs text-gray-500 line-clamp-1" title={company.razão_social}>
                    {company.razão_social}
                </p>
            )}
        </div>
        <button className="text-gray-400 hover:text-nexus-dark p-1 rounded hover:bg-gray-100 transition-colors">
            <MoreHorizontal className="w-5 h-5" />
        </button>
      </div>

      {/* Properties Grid */}
      <div className="px-5 py-2 flex-grow space-y-3">

        {/* Source Badge */}
        <div className="flex items-center gap-2">
            <span className={`text-[10px] px-2 py-0.5 rounded font-bold uppercase tracking-wide border ${
                company.source === 'GOOGLE_MAPS' ? 'bg-blue-50 text-blue-700 border-blue-100' :
                company.source === 'GOV_DATA' ? 'bg-orange-50 text-orange-700 border-orange-100' :
                'bg-gray-50 text-gray-600 border-gray-100'
            }`}>
                {company.source.replace(/_/g, ' ')}
            </span>
        </div>

        <div className="h-px bg-gray-100 my-2"></div>

        {/* Data Rows */}
        <div className="space-y-2.5">
            {/* Location */}
            <div className="flex items-start gap-3">
                <MapPin className="w-4 h-4 text-gray-400 mt-0.5 shrink-0" />
                <div className="flex flex-col">
                    <span 
                        className="text-xs font-medium text-gray-700 line-clamp-2" 
                        title={company.endereco}
                    >
                        {company.endereco || company.cidade}
                    </span>
                    {!company.endereco && company.bairro && <span className="text-[10px] text-gray-500">{company.bairro}</span>}
                </div>
            </div>

            {/* Phone & WhatsApp */}
             <div className="flex items-center gap-3">
                <Phone className="w-4 h-4 text-gray-400 shrink-0" />
                <span className="text-xs font-medium text-gray-700 select-all truncate">
                    {company.telefone || <span className="text-gray-400 italic">--</span>}
                </span>
                {company.telefone && (
                    <button 
                        onClick={(e) => openWhatsApp(e, company.telefone!)}
                        className="p-1 text-green-600 hover:bg-green-50 rounded-full transition-colors ml-auto flex items-center gap-1 text-[10px] font-bold border border-transparent hover:border-green-200"
                        title="Conversar no WhatsApp"
                    >
                        <MessageCircle className="w-3.5 h-3.5" />
                        <span className="hidden group-hover:inline">WhatsApp</span>
                    </button>
                )}
            </div>

            {/* Website */}
            <div className="flex items-center gap-3">
                <Globe className="w-4 h-4 text-gray-400 shrink-0" />
                {company.website ? (
                    <span 
                        onClick={openWebsite} 
                        className="text-xs font-medium text-nexus-royal hover:underline cursor-pointer truncate max-w-[180px]"
                    >
                        {company.website}
                    </span>
                ) : (
                    <span className="text-xs text-gray-400 italic">--</span>
                )}
            </div>

            {/* Hours */}
            <div className="flex items-center gap-3">
                <Clock className="w-4 h-4 text-gray-400 shrink-0" />
                <span className="text-xs text-gray-600 truncate">
                    {company.opening_hours || <span className="text-gray-400 italic">{t.hours_unavailable}</span>}
                </span>
            </div>
        </div>
      </div>

      {/* Footer Actions */}
      <div className="px-5 py-4 mt-2 border-t border-gray-100 bg-gray-50/50 flex items-center justify-between">

          <div className="flex items-center gap-3">
             {/* CNPJ Copy */}
             <div 
                className="flex items-center gap-1.5 cursor-pointer group/copy"
                onClick={copyCnpj}
                title="Copiar CNPJ"
             >
                <span className="text-[10px] font-mono text-gray-400 group-hover/copy:text-gray-600 transition-colors">
                    {company.cnpj}
                </span>
                {copied ? <Check className="w-3 h-3 text-emerald-500" /> : <Copy className="w-3 h-3 text-gray-300 group-hover/copy:text-gray-500" />}
             </div>

             {/* Google Maps External Link */}
             <button 
                onClick={openGoogleMaps}
                title="Ver no Google Maps"
                className="text-gray-400 hover:text-nexus-royal transition-colors"
             >
                 <Map className="w-3.5 h-3.5" />
             </button>
          </div>

          <div className="flex items-center gap-2">
            {/* Pipeline Button */}
            <button 
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); if(!isInPipeline) onAddToPipeline(company); }}
                title={isInPipeline ? "Já no pipeline" : "Adicionar ao Pipeline"}
                className={`flex items-center gap-1.5 text-xs font-bold px-3 py-1.5 rounded transition-all border shadow-sm ${
                    isInPipeline 
                    ? 'bg-purple-50 text-purple-700 border-purple-200 cursor-default' 
                    : 'bg-white text-gray-600 border-gray-200 hover:border-purple-300 hover:text-purple-600 hover:bg-purple-50'
                }`}
            >
                {isInPipeline ? (
                    <>
                    <Check className="w-3.5 h-3.5" />
                    </>
                ) : (
                    <>
                    <Kanban className="w-3.5 h-3.5" /> {t.actions_pipeline}
                    </>
                )}
            </button>

            {/* Save List Button */}
            <button 
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); onSaveClick(company); }}
                className={`flex items-center gap-1.5 text-xs font-bold px-3 py-1.5 rounded transition-all border shadow-sm ${
                    isSaved 
                    ? 'bg-emerald-50 text-emerald-700 border-emerald-200 hover:bg-emerald-100' 
                    : 'bg-white text-nexus-royal border-gray-200 hover:border-nexus-royal hover:bg-blue-50'
                }`}>
                {isSaved ? (
                    <>
                    <Check className="w-3.5 h-3.5" /> {t.actions_saved}
                    </>
                ) : (
                    <>
                    <Plus className="w-3.5 h-3.5" /> {t.actions_save}
                    </>
                )}
            </button>
          </div>
      </div>
    </div>
  );
};

